const todayCST = () => new Date().toLocaleDateString("en-CA", { timeZone: "America/Chicago" });
const tsToCST = (ts) => new Date(ts).toLocaleDateString("en-CA", { timeZone: "America/Chicago" });
const todayStr = todayCST; // alias
const normalizeSchedulableJobDate = (date) => (!date || date < todayCST() ? todayCST() : date);
const normalizeEnergySealLabel = (label) => String(label || "").trim().toLowerCase() === "energy seal technician" ? "Energy Seal Van" : label;
const truckDisplayName = (tr) => normalizeEnergySealLabel(tr?.vehicleName || tr?.members || tr?.name) || "Truck";
const naturalSort = (a, b) => truckDisplayName(a).localeCompare(truckDisplayName(b), undefined, { numeric: true, sensitivity: "base" });
const timeStr = () => new Date().toLocaleTimeString("en-US", { hour: "numeric", minute: "2-digit" });
const dateStr = (iso) => { try { return new Date(iso).toLocaleDateString("en-US", { month: "short", day: "numeric", hour: "numeric", minute: "2-digit" }); } catch { return ""; } };
const toJsDate = (value) => {
  if (!value) return null;
  if (value instanceof Date) return value;
  if (typeof value?.toDate === "function") return value.toDate();
  if (typeof value?.seconds === "number") return new Date(value.seconds * 1000);
  const parsed = new Date(value);
  return Number.isNaN(parsed.getTime()) ? null : parsed;
};
const formatChecklistTime = (value) => {
  const date = toJsDate(value);
  if (!date) return "—";
  return date.toLocaleTimeString("en-US", {
    hour: "numeric",
    minute: "2-digit",
    hour12: true,
    timeZone: "America/Chicago",
  });
};
const formatChecklistDayDate = (isoDate) => {
  const date = isoDate ? new Date(`${isoDate}T12:00:00`) : null;
  if (!date || Number.isNaN(date.getTime())) return { dayLabel: "", dateLabel: "" };
  return {
    dayLabel: date.toLocaleDateString("en-US", { weekday: "short", timeZone: "America/Chicago" }),
    dateLabel: date.toLocaleDateString("en-US", { month: "short", day: "numeric", timeZone: "America/Chicago" }),
  };
};
const getCurrentWorkWeekDates = () => {
  const now = new Date();
  const local = new Date(now.toLocaleString("en-US", { timeZone: "America/Chicago" }));
  const day = local.getDay();
  const diffToMonday = day === 0 ? -6 : 1 - day;
  const monday = new Date(local);
  monday.setHours(12, 0, 0, 0);
  monday.setDate(local.getDate() + diffToMonday);
  return Array.from({ length: 5 }, (_, index) => {
    const date = new Date(monday);
    date.setDate(monday.getDate() + index);
    return date.toLocaleDateString("en-CA", { timeZone: "America/Chicago" });
  });
};
const mapsUrl = (addr) => `https://maps.apple.com/?daddr=${encodeURIComponent(addr)}`;

function haversineKm(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const dLat = (lat2-lat1)*Math.PI/180;
  const dLon = (lon2-lon1)*Math.PI/180;
  const a = Math.sin(dLat/2)**2 + Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.sin(dLon/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}
function kmToMiles(km) { return km * 0.621371; }
function getGeocache(addr) {
  try {
    const cache = JSON.parse(sessionStorage.getItem("ist_geocache") || "{}");
    return cache[addr] || null;
  } catch { return null; }
}

