function Badge({ children, color, bg }) {
  return <span style={{ display: "inline-block", padding: "3px 10px", borderRadius: "99px", fontSize: "11px", fontWeight: 700, letterSpacing: "0.3px", textTransform: "uppercase", color: color || t.accent, background: bg || t.accentBg, whiteSpace: "nowrap" }}>{children}</span>;
}

function Button({ children, onClick, variant = "primary", style: s, disabled }) {
  const base = { padding: "11px 20px", border: "none", borderRadius: "14px", fontWeight: 750, fontSize: "14px", cursor: disabled ? "not-allowed" : "pointer", transition: "all 0.15s ease", opacity: disabled ? 0.45 : 1, fontFamily: "inherit", minHeight: "44px", display: "inline-flex", alignItems: "center", justifyContent: "center" };
  const v = {
    primary: { background: "linear-gradient(135deg,#2563eb,#1d4ed8)", color: "#fff", boxShadow: "0 12px 28px rgba(37,99,235,0.28)" },
    secondary: { background: "rgba(255,255,255,0.9)", color: t.textSecondary, border: "1px solid " + t.border, boxShadow: "0 8px 20px rgba(15,23,42,0.05)" },
    danger: { background: t.dangerBg, color: t.danger, border: "1px solid #fecaca" },
    ghost: { background: "transparent", color: t.textMuted, padding: "8px 12px", minHeight: "36px" },
  };
  return <button onClick={onClick} disabled={disabled} style={{ ...base, ...v[variant], ...s }}>{children}</button>;
}

function Input({ label, ...props }) {
  return (
    <div style={{ marginBottom: "16px" }}>
      {label && <label style={{ display: "block", fontSize: "12px", fontWeight: 500, color: t.textSecondary, marginBottom: "5px" }}>{label}</label>}
      <input {...props} style={{ width: "100%", padding: "11px 13px", background: "rgba(255,255,255,0.92)", border: "1px solid " + t.border, borderRadius: "12px", color: t.text, fontSize: "14px", fontFamily: "inherit", outline: "none", boxSizing: "border-box", boxShadow: "inset 0 1px 0 rgba(255,255,255,0.8)", ...(props.style || {}) }} onFocus={(e) => { e.target.style.borderColor = t.accent; e.target.style.boxShadow = "0 0 0 4px rgba(37,99,235,0.12)"; setTimeout(() => e.target.scrollIntoView({ behavior: "smooth", block: "nearest" }), 320); }} onBlur={(e) => { e.target.style.borderColor = t.border; e.target.style.boxShadow = "inset 0 1px 0 rgba(255,255,255,0.8)"; }} />
    </div>
  );
}

