    updatesSnap.forEach(async (d) => { await deleteDoc(doc(db, "updates", d.id)); });
    const pmSnap = await getDocs(query(collection(db, "pmUpdates"), where("jobId", "==", id)));
    pmSnap.forEach(async (d) => { await deleteDoc(doc(db, "pmUpdates", d.id)); });
